const level = 'beginner';
const levelName = 'Débutant';
const user = $node["Boucle par User"].json;
const puzzlesData = $node["🧩 Générer Puzzles du Jour"].json;

// Debug: verify structure
const puzzles = puzzlesData.puzzles || puzzlesData;
const puzzle = puzzles[level];

const boardImageUrl = `https://fen2image.chessvision.ai/?fen=${encodeURIComponent(puzzle.fen)}`;
const puzzleUrl = `http://localhost:3000/puzzle?id=${puzzle.id}`;

const html = `
<div style="background-color: #141311; color: #ffffff; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif; padding: 60px 20px; text-align: center;">
  <div style="max-width: 600px; margin: 0 auto;">
    <h1 style="color: #a0d660; font-size: 32px; letter-spacing: -0.02em; margin-bottom: 24px; font-weight: 800; text-transform: uppercase;">Tactical Precision</h1>

    <p style="font-size: 18px; color: #E5E7EB; line-height: 1.6; margin-bottom: 40px;">
      Bonjour <b>${user.username}</b>,<br/>
      Votre esprit stratégique est requis. Voici votre défi quotidien.
    </p>

    <div style="background-color: #1c1a17; padding: 32px; border-radius: 12px; margin-bottom: 40px;">
      <img src="${boardImageUrl}" width="100%" style="max-width: 400px; border-radius: 4px; box-shadow: 0px 12px 32px rgba(0, 0, 0, 0.4);" />

      <div style="margin-top: 24px;">
        <span style="color: #a0d660; font-size: 12px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.1em; background: rgba(160, 214, 96, 0.1); padding: 4px 12px; border-radius: 9999px;">
          Niveau: ${levelName}
        </span>
        <span style="color: #9CA3AF; font-size: 12px; margin-left: 12px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.1em;">
          ELO: ${puzzle.rating}
        </span>
      </div>
    </div>

    <a href="${puzzleUrl}" style="background: linear-gradient(135deg, #a0d660 0%, #82b644 100%); color: #141311; padding: 20px 40px; border-radius: 8px; text-decoration: none; font-weight: 800; font-size: 16px; display: inline-block; letter-spacing: 0.05em;">
      DÉBUTER L'ANALYSE
    </a>

    <div style="margin-top: 60px; border-top: 1px solid rgba(255,255,255,0.05); padding-top: 30px;">
      <p style="color: #4B5563; font-size: 11px; text-transform: uppercase; letter-spacing: 0.2em;">
        Chess Platform | The Grandmaster\'s Study
      </p>
    </div>
  </div>
</div>
`;

return { email: user.email, htmlBody: html, subject: `Challenge Quotidien [${levelName}] — Chess Platform` };

